import React, { useState, useEffect } from 'react';
import { Camera, Image as ImageIcon, Video, Mail, Phone, MapPin, Menu, X, ChevronRight, Globe, Maximize2, MessageCircle, CheckCircle2 } from 'lucide-react';

const InstagramIcon = ({ className }) => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <rect x="2" y="2" width="20" height="20" rx="5" ry="5"></rect>
    <path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"></path>
    <line x1="17.5" y1="6.5" x2="17.51" y2="6.5"></line>
  </svg>
);

const App = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [lang, setLang] = useState('ar');

  // Hayde el-function hiye el-ser! Bi-tkhalli el-suwar t-bayyen bel-VS Code w GitHub
  const getImg = (imgName) => {
    const baseUrl = process.env.PUBLIC_URL || '';
    return `${baseUrl}/img/${imgName}`;
  };

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const content = {
    en: {
      nav: ['Services', 'Portfolio', 'Contact'],
      hero: { title: 'Capturing Moments', subtitle: 'Professional Photography', cta: 'Book Now' },
      services: [
        { title: 'Commercial', img: getImg('service1.jpg'), desc: 'High-end product photography' },
        { title: 'Events', img: getImg('service2.jpg'), desc: 'Weddings and corporate events' },
        { title: 'Video', img: getImg('service3.jpg'), desc: 'Cinematic storytelling' }
      ]
    },
    ar: {
      nav: ['خدماتنا', 'أعمالنا', 'اتصل بنا'],
      hero: { title: 'نخلد اللحظات', subtitle: 'تصوير فوتوغرافي احترافي', cta: 'احجز الآن' },
      services: [
        { title: 'تصوير تجاري', img: getImg('service1.jpg'), desc: 'تصوير منتجات احترافي' },
        { title: 'مناسبات', img: getImg('service2.jpg'), desc: 'تغطية أعراس ومناسبات' },
        { title: 'إنتاج فيديو', img: getImg('service3.jpg'), desc: 'صناعة محتوى مرئي' }
      ]
    }
  };

  return (
    <div className={`min-h-screen bg-[#0a0a0a] text-white ${lang === 'ar' ? 'rtl text-right' : 'ltr text-left'}`}>

      {/* Navbar */}
      <nav className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-black/90 backdrop-blur-md py-4' : 'bg-transparent py-6'}`}>
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <img src={getImg('logo.png')} alt="Logo" className="h-12 w-auto" />
          <div className="hidden md:flex items-center gap-8">
             {content[lang].nav.map((item, i) => (
               <a key={i} href={`#${item}`} className="hover:text-pink-500 transition-colors">{item}</a>
             ))}
             <button onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')} className="p-2 border border-white/20 rounded-full hover:bg-white/10 transition-all">
               <Globe className="w-5 h-5" />
             </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative h-screen flex items-center justify-center overflow-hidden">
        <img 
          src={getImg('hero.jpg')} 
          className="absolute inset-0 w-full h-full object-cover opacity-60 scale-105 animate-pulse" 
          alt="Hero"
          style={{ animationDuration: '8s' }}
          onError={(e) => { e.target.src = 'https://via.placeholder.com/1920x1080?text=Hero+Image+Missing'; }}
        />
        <div className="relative z-10 text-center px-4">
          <h1 className="text-6xl md:text-8xl font-bold mb-6 tracking-tighter">{content[lang].hero.title}</h1>
          <p className="text-xl md:text-2xl text-gray-300 mb-10 max-w-2xl mx-auto">{content[lang].hero.subtitle}</p>
          <button className="bg-white text-black px-10 py-4 rounded-full font-bold hover:bg-pink-500 hover:text-white transition-all duration-300">
            {content[lang].hero.cta}
          </button>
        </div>
      </section>

      {/* Services Section */}
      <section id="services" className="py-24 px-6 bg-[#0d0d0d]">
        <div className="max-w-7xl mx-auto">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
            {content[lang].services.map((service, index) => (
              <div key={index} className="group rounded-2xl overflow-hidden bg-white/5 border border-white/10">
                <div className="aspect-[4/5] overflow-hidden">
                  <img 
                    src={service.img} 
                    alt={service.title}
                    className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                    onError={(e) => { e.target.src = 'https://via.placeholder.com/400x600?text=Service+Image'; }}
                  />
                </div>
                <div className="p-8">
                  <h3 className="text-2xl font-bold mb-3">{service.title}</h3>
                  <p className="text-gray-400">{service.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Contact Simple */}
      <section className="py-20 text-center border-t border-white/10">
        <div className="flex justify-center gap-6">
          <MessageCircle className="w-10 h-10 text-green-500 cursor-pointer" />
          <InstagramIcon className="w-10 h-10 text-pink-500 cursor-pointer" />
        </div>
      </section>

    </div>
  );
};

export default App;
